  const { stdout } = await execFileAsync('which', [commandName], {
    timeout: 5000,
    maxBuffer: 16 * 1024
  });
  const binPath = (stdout || '').trim().split('\n')[0];
  if (!binPath) throw new Error('NOT_FOUND');
  return binPath;
}

